    def bfs(self, start):
        if start not in self._adj:
            raise RuntimeError(f"graph_bfs: node {start!r} not found")
        visited = []
        seen = {start}
        queue = deque([start])
        while queue:
            node = queue.popleft()
            visited.append(node)
            for nb, _ in sorted(self._adj.get(node, set()), key=lambda x: str(x[0])):
                if nb not in seen:
                    seen.add(nb)
