    def dfs(self, start):
        if start not in self._adj:
            raise RuntimeError(f"graph_dfs: node {start!r} not found")
        visited = []
        seen = set()
        stack = [start]
        while stack:
            node = stack.pop()
            if node in seen:
                continue
            seen.add(node)
            visited.append(node)
            for nb, _ in sorted(self._adj.get(node, set()), key=lambda x: str(x[0]), reverse=True):
