class _SrvLinkedList:
    """Doubly-linked list data structure for sauravcode."""
    __slots__ = ('_head', '_tail', '_size')
    def __init__(self, items=None):
        self._head = None
        self._tail = None
        self._size = 0
        if items:
            for item in items:
                self.push_back(item)
    def push_front(self, val):
        node = _SrvLLNode(val, nxt=self._head)
        if self._head:
            self._head.prev = node
        self._head = node
        if self._tail is None:
            self._tail = node
        self._size += 1
    def push_back(self, val):
        node = _SrvLLNode(val, prev=self._tail)
        if self._tail:
            self._tail.next = node
        self._tail = node
        if self._head is None:
            self._head = node
        self._size += 1
    def pop_front(self):
        if not self._head:
            raise RuntimeError("ll_pop_front: list is empty")
        val = self._head.value
        self._head = self._head.next
        if self._head:
            self._head.prev = None
        else:
            self._tail = None
        self._size -= 1
        return val
    def pop_back(self):
        if not self._tail:
            raise RuntimeError("ll_pop_back: list is empty")
        val = self._tail.value

